%[text] # Code Test
%[text] ## Seeds Initialization
my_robot;

Robot.display; %[output:0f41b501]

N = 1001;
angles = linspace(-pi, pi, N);
xlimit = [-pi, pi];
lbls = {'-\pi', '-3\pi/4', '-\pi/2', '-\pi/4', '0', '\pi/4', '\pi/2', '3\pi/4', '\pi'};

QSolution = zeros(N, 6);

% Values [-π, π]
for k = 1:6
    QSolution(:, k) = -pi + (2*pi/(N-1)) * (0:N-1)';
end

% Random values
% for k = 1:6
%     QSolution(:, k) = -pi + 2*pi * rand(N, 1);
% end

hat = Robot.offset';
Robot.offset = zeros(6, 1);

Target = Robot.fkine(QSolution);

T_tool = Robot.tool;

a1 = Robot.links(1).a; 
a2 = Robot.links(2).a; 
a3 = Robot.links(3).a; 

d1 = Robot.links(1).d; 
d4 = Robot.links(4).d; 
d6 = Robot.links(6).d; 

L1 = a2; 
L2 = sqrt(a3^2 + d4^2);



T06   = repmat(SE3(), N, 1);
T03   = repmat(SE3(), N, 1);
p_w   = zeros(N, 3);

q1    = zeros(N, 2);
q2    = zeros(N, 4);
q3    = zeros(N, 4);

q4    = zeros(N, 2);
q5    = zeros(N, 2);
q6    = zeros(N, 2);

err_q1    = zeros(N, 2);
err_q2    = zeros(N, 4);
err_q3    = zeros(N, 4);
err_q4    = zeros(N, 2);
err_q5    = zeros(N, 2);
err_q6    = zeros(N, 2);

phi = atan2(a3, d4); 

%%
%[text] ## Solution $q\_1$
for k = 1:N
    T06(k) = Target(k) / T_tool; 
    
    % Kinematic Decoupling:
    % p_w = p - d6 * z
    pos_tcp = T06(k).t;
    z_tcp   = T06(k).a;
    
    p_w(k, :) = (pos_tcp - z_tcp * d6)';
    
    if norm(p_w(k, 1:2)) < 1e-6
        disp('Advertencia: Punto sobre el eje Z0 (Singularidad)')
    end
    
    q1(k, 1) = atan2(p_w(k, 2), p_w(k, 1));
    q1(k, 2) = atan2(-p_w(k, 2), -p_w(k, 1));
end


err_q1(:, 1) = rad2deg(((QSolution(:, 1) - q1(:, 1))));
err_q1(:, 2) = rad2deg(((QSolution(:, 1) - q1(:, 2))));

figure('Name', "Error q1");  %[output:0d7188fe]
plot(angles, [err_q1(:, 1) err_q1(:, 2)], 'LineWidth', 1); %[output:0d7188fe]

title('Error Absoluto q_1'); xlabel('Ángulo [rad]'); ylabel('Error Relativo [deg]'); %[output:0d7188fe]

lgd = legend('e_{1}', 'e_{2}', 'Location', 'northeastoutside'); %[output:0d7188fe]
lgd.ItemHitFcn = @toggleSignal;

xlim(xlimit); %[output:0d7188fe]
set(gca, 'XTick', -pi : pi/4 : pi); %[output:0d7188fe]
set(gca, 'XTickLabel', lbls, 'TickLabelInterpreter', 'tex'); %[output:0d7188fe]

grid on;grid minor; %[output:0d7188fe]

%%
%[text] ## Solution $q\_2, q\_3$
for k = 1:N
    r     = zeros(2, 1);
    D     = zeros(2, 1);
    alpha = zeros(2, 1);

    px = p_w(k, 1);
    py = p_w(k, 2);
    pz = p_w(k, 3);

    % Front Configuration
    r(1) =  sqrt(px^2 + py^2) - a1; 
    % Back Configuration
    r(2) = -sqrt(px^2 + py^2) - a1;
    
    s = pz - d1; 


    for j = 1:2
        D(j)     = sqrt(r(j)^2 + s^2);
        alpha(j) = atan2(s, r(j));
        
        % j=1 -> idx1=1, idx2=2
        % j=2 -> idx1=3, idx2=4
        
        idx1 = 2*j - 1;
        idx2 = 2*j;

        if D(j) <= (L1 + L2) && D(j) >= abs(L1 - L2)
            beta  = Tcoseno_a(L1, L2, D(j));
            gamma = Tcoseno_a(D(j), L1, L2);

            % Elbow Up
            q2(k, idx1) = alpha(j) + gamma;
            q3(k, idx1) = beta - pi/2 - phi;

            % Elbow Down
            q2(k, idx2) = alpha(j) - gamma;
            q3(k, idx2) = -beta + pi/2 - phi;
        else
            q2(k, idx1:idx2) = NaN;
            q3(k, idx1:idx2) = NaN;
        end
    end
end

err_q2(:, 1) = rad2deg((QSolution(:, 2) - q2(:, 1)));
err_q2(:, 2) = rad2deg((QSolution(:, 2) - q2(:, 2)));
err_q2(:, 3) = rad2deg((QSolution(:, 2) - q2(:, 3)));
err_q2(:, 4) = rad2deg((QSolution(:, 2) - q2(:, 4)));

figure('Name', "Error q2");  %[output:68f36ec9]

plot(angles, [err_q2(:, 1) err_q2(:, 2) err_q2(:, 3) err_q2(:, 4)], 'LineWidth', 1); %[output:68f36ec9]

title('Error Absoluto q_2'); xlabel('Ángulo [rad]'); ylabel('Error Relativo [deg]'); %[output:68f36ec9]

lgd2 = legend('e_{1}', 'e_{2}', 'e_{3}', 'e_{4}', 'Location', 'northeastoutside'); %[output:68f36ec9]
lgd2.ItemHitFcn = @toggleSignal;

xlim(xlimit); %[output:68f36ec9]
set(gca, 'XTick', -pi : pi/4 : pi); %[output:68f36ec9]
set(gca, 'XTickLabel', lbls, 'TickLabelInterpreter', 'tex'); %[output:68f36ec9]


grid on;grid minor; %[output:68f36ec9]

err_q3(:, 1) = rad2deg((QSolution(:, 3) - q3(:, 1)));
err_q3(:, 2) = rad2deg((QSolution(:, 3) - q3(:, 2)));
err_q3(:, 3) = rad2deg((QSolution(:, 3) - q3(:, 3)));
err_q3(:, 4) = rad2deg((QSolution(:, 3) - q3(:, 4)));

figure('Name', "Error q3");  %[output:2b768b64]

plot(angles, [err_q3(:, 1) err_q3(:, 2) err_q3(:, 3) err_q3(:, 4)], 'LineWidth', 1); %[output:2b768b64]

title('Error Absoluto q_3'); xlabel('Ángulo [rad]'); ylabel('Error Relativo [deg]'); %[output:2b768b64]
lgd3 = legend('e_{1}', 'e_{2}', 'e_{3}', 'e_{4}', 'Location', 'northeastoutside'); %[output:2b768b64]
lgd3.ItemHitFcn = @toggleSignal;

xlim(xlimit); %[output:2b768b64]
set(gca, 'XTick', -pi : pi/4 : pi); %[output:2b768b64]
set(gca, 'XTickLabel', lbls, 'TickLabelInterpreter', 'tex'); %[output:2b768b64]

grid on;grid minor; %[output:2b768b64]
%%
%[text] ## Solution $q\_4, q\_5, q\_6$
% Robot with only the first 3 Links
robot_sub = SerialLink(Robot.links(1:3));

for k = 1:N
    % Testing articular vector, only used to test the logic
    % for the I.K. code
    q = [QSolution(k, 1), QSolution(k, 2), QSolution(k, 3)];

    % F.K. Robot with only the first 3 Links
    T03(k) = robot_sub.fkine(q);

    R03 = T03(k).R; R06 = T06(k).R;
    
    % Roation Matrix R36
    r = R03 \ R06; 

    % Wrist Up
    q5(k, 1) = atan2(norm([r(1, 3), r(2, 3)]), r(3, 3));
    q4(k, 1) = atan2(r(2, 3), r(1, 3));
    q6(k, 1) = atan2(r(3, 2), -r(3, 1));

    % Wrist Down
    q5(k, 2) = atan2(-norm([r(1, 3), r(2, 3)]), r(3, 3));
    q4(k, 2) = atan2(-r(2, 3), -r(1, 3)); 
    q6(k, 2) = atan2(-r(3, 2), r(3, 1)); 
end

err_q4(:, 1) = rad2deg((QSolution(:, 4) - q4(:, 1)));
err_q4(:, 2) = rad2deg((QSolution(:, 4) - q4(:, 2)));

figure('Name', "Error q4");  %[output:26e1a630]

plot(angles, [err_q4(:, 1) err_q4(:, 2)], 'LineWidth', 1); %[output:26e1a630]

title('Error Absoluto q_4'); xlabel('Ángulo [rad]'); ylabel('Error Relativo [deg]'); %[output:26e1a630]
lgd4 = legend('e_{1}', 'e_{2}', 'Location', 'northeastoutside'); %[output:26e1a630]
lgd4.ItemHitFcn = @toggleSignal;

xlim(xlimit); %[output:26e1a630]
set(gca, 'XTick', -pi : pi/4 : pi); %[output:26e1a630]
set(gca, 'XTickLabel', lbls, 'TickLabelInterpreter', 'tex'); %[output:26e1a630]

grid on;grid minor; %[output:26e1a630]

err_q5(:, 1) = rad2deg((QSolution(:, 5) - q5(:, 1)));
err_q5(:, 2) = rad2deg((QSolution(:, 5) - q5(:, 2)));

figure('Name', "Error q5");  %[output:4b881d4f]

plot(angles, [err_q5(:, 1) err_q5(:, 2)], 'LineWidth', 1); %[output:4b881d4f]

title('Error Absoluto q_5'); xlabel('Ángulo [rad]'); ylabel('Error Relativo [deg]'); %[output:4b881d4f]
lgd5 = legend('e_{1}', 'e_{2}', 'Location', 'northeastoutside'); %[output:4b881d4f]
lgd5.ItemHitFcn = @toggleSignal;

xlim(xlimit); %[output:4b881d4f]
set(gca, 'XTick', -pi : pi/4 : pi); %[output:4b881d4f]
set(gca, 'XTickLabel', lbls, 'TickLabelInterpreter', 'tex'); %[output:4b881d4f]

grid on;grid minor; %[output:4b881d4f]

err_q6(:, 1) = rad2deg((QSolution(:, 6) - q6(:, 1)));
err_q6(:, 2) = rad2deg((QSolution(:, 6) - q6(:, 2)));

figure('Name', "Error q6");  %[output:1df512f6]

plot(angles, [err_q6(:, 1) err_q6(:, 2)], 'LineWidth', 1); %[output:1df512f6]

title('Error Absoluto q_6'); xlabel('Ángulo [rad]'); ylabel('Error Relativo [deg]'); %[output:1df512f6]
lgd6 = legend('e_{1}', 'e_{2}', 'Location', 'northeastoutside'); %[output:1df512f6]
lgd6.ItemHitFcn = @toggleSignal;

xlim(xlimit); %[output:1df512f6]
set(gca, 'XTick', -pi : pi/4 : pi); %[output:1df512f6]
set(gca, 'XTickLabel', lbls, 'TickLabelInterpreter', 'tex'); %[output:1df512f6]

grid on;grid minor; %[output:1df512f6]
%%
%[text] ## Cartesian Error
my_QSolution = zeros(N, 6, 8);

% --- q1  ---
my_QSolution(:, 1, 1:4) = repmat(q1(:, 1), 1, 1, 4);
my_QSolution(:, 1, 5:8) = repmat(q1(:, 2), 1, 1, 4);

% --- q2 ---
my_QSolution(:, 2, 1:2) = repmat(q2(:, 1), 1, 1, 2);
my_QSolution(:, 2, 3:4) = repmat(q2(:, 2), 1, 1, 2);
my_QSolution(:, 2, 5:6) = repmat(q2(:, 3), 1, 1, 2);
my_QSolution(:, 2, 7:8) = repmat(q2(:, 4), 1, 1, 2);

% --- q3  ---
my_QSolution(:, 3, 1:2) = repmat(q3(:, 1), 1, 1, 2);
my_QSolution(:, 3, 3:4) = repmat(q3(:, 2), 1, 1, 2);
my_QSolution(:, 3, 5:6) = repmat(q3(:, 3), 1, 1, 2);
my_QSolution(:, 3, 7:8) = repmat(q3(:, 4), 1, 1, 2);

% --- q4  ---
my_QSolution(:, 4, 1:4) = repmat(q4(:, 1), 1, 1, 4);
my_QSolution(:, 4, 5:8) = repmat(q4(:, 2), 1, 1, 4);

% --- q5  ---
my_QSolution(:, 5, 1:4) = repmat(q5(:, 1), 1, 1, 4);
my_QSolution(:, 5, 5:8) = repmat(q5(:, 2), 1, 1, 4);

% --- q6  ---
my_QSolution(:, 6, 1:4) = repmat(q6(:, 1), 1, 1, 4);
my_QSolution(:, 6, 5:8) = repmat(q6(:, 2), 1, 1, 4);

%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%

e_pos = zeros(N, 8);
e_ori = zeros(N, 8);

for sol = 1:8
    for k = 1:N
        q_current = my_QSolution(k, :, sol);

        % Protection against NaN results
        if any(isnan(q_current))
            e_pos(k, sol) = NaN; 
            e_ori(k, sol) = NaN;
            continue;
        end

        T_myIK = Robot.fkine(q_current);

        p_sol = T_myIK.t; 
        R_sol = T_myIK.R; 

        p_target = Target(k).t;
        R_target = Target(k).R;
        
        % Position Error
        e_pos(k, sol) = norm(p_target - p_sol) * 1000; 
        
        % Orientation Error
        R_err = R_target * R_sol'; 
        e_ori(k, sol) = real(acos( (trace(R_err) - 1) / 2 )); 
    end
end


figure('Name', 'Position Cartesian Error', 'Color', 'w'); %[output:14c56773]

% Position Error Graph
plot(angles, e_pos, 'LineWidth', 1.5); %[output:14c56773]
title('Error Cartesiano de Posición Absoluta', 'Interpreter', 'tex'); %[output:14c56773]
ylabel('Error [mm]'); %[output:14c56773]

xlim(xlimit); %[output:14c56773]
set(gca, 'XTick', -pi : pi/4 : pi); %[output:14c56773]
set(gca, 'XTickLabel', lbls, 'TickLabelInterpreter', 'tex'); %[output:14c56773]

grid on;grid minor; %[output:14c56773]

lgd_ep = legend('Sol 1', 'Sol 2', 'Sol 3', 'Sol 4', 'Sol 5', 'Sol 6', 'Sol 7', 'Sol 8', 'Location', 'eastoutside'); %[output:14c56773]
lgd_ep.ItemHitFcn = @toggleSignal;

% Orientation Error Graph
figure('Name', 'Orientation Cartesian Error', 'Color', 'w'); %[output:570ed031]

plot(angles, rad2deg(e_ori), 'LineWidth', 1.5);  %[output:570ed031]
title('Error Cartesiano de Orientación Absoluta', 'Interpreter', 'tex'); %[output:570ed031]
xlabel('Trayectoria [rad]'); ylabel('Error [deg]'); %[output:570ed031]

xlim(xlimit); %[output:570ed031]
set(gca, 'XTick', -pi : pi/4 : pi); %[output:570ed031]
set(gca, 'XTickLabel', lbls, 'TickLabelInterpreter', 'tex'); %[output:570ed031]

lgd_er = legend('Sol 1', 'Sol 2', 'Sol 3', 'Sol 4', 'Sol 5', 'Sol 6', 'Sol 7', 'Sol 8', 'Location', 'eastoutside'); %[output:570ed031]
lgd_er.ItemHitFcn = @toggleSignal;


grid on;grid minor; %[output:570ed031]
%%
%[text] ## Jacobian Unit Test
clear; close all;

my_robot; Robot.display; %[output:8e451ea2]

%%
%[text] ## Save Variables
% writematrix(err_q4, 'error_q4.csv');
% writematrix(err_q3, 'error_q3.csv');
% writematrix(error12, 'error12.csv');
